use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

struct Inventory {
    stock_levels: Arc<Mutex<i32>>,
}

impl Inventory {
    fn new(stock_level: i32) -> Self {
        Inventory {
            stock_levels: Arc::new(Mutex::new(stock_level)),
        }
    }

    fn check_stock(&self, product_id: &str) -> bool {
        let stock = self.stock_levels.lock().unwrap();
        *stock > 0
    }

    fn decrement_inventory(&self, product_id: &str) {
        let mut stock = self.stock_levels.lock().unwrap();
        *stock -= 1;
    }
}

fn main() {
    let inventory = Inventory::new(100);

    let handle1 = thread::spawn(move || {
        for _ in 0..10 {
            if inventory.check_stock("product1") {
                inventory.decrement_inventory("product1");
            } else {
                println!("Product out of stock.");
            }
            thread::sleep(Duration::from_millis(100));
        }
    });

    let handle2 = thread::spawn(move || {
        for _ in 0..10 {
            if inventory.check_stock("product1") {
                inventory.decrement_inventory("product1");
            } else {
                println!("Product out of stock.");
            }
            thread::sleep(Duration::from_millis(100));
        }
    });

    handle1.join().unwrap();
    handle2.join().unwrap();

    let final_stock = *inventory.stock_levels.lock().unwrap();
    assert_eq!(final_stock, 0);
}